// Get data from both HTTP nodes using $('Node Name')
let invoices = [];
let payments = [];

try {
  const invResp = $('GET Unpaid Invoices').first().json;
  invoices = Array.isArray(invResp) ? invResp : (invResp.data || invResp.invoices || []);
} catch (e) {
  console.log('Failed to fetch invoices:', e.message);
}

try {
  const payResp = $('GET Recent Payments').first().json;
  payments = Array.isArray(payResp) ? payResp : (payResp.data || payResp.transactions || []);
} catch (e) {
  console.log('Failed to fetch payments:', e.message);
}

if (!invoices.length) {
  return [{ json: { matchedCount: 0, unmatchedCount: 0, overdueCount: 0, updates: [], message: 'No unpaid invoices found' } }];
}

const updates = [];
const matched = [];
const unmatched = [];

// Match payments to invoices
payments.forEach(payment => {
  let matchedInvoice = null;

  // 1. Direct reference match
  if (payment.invoice_id || payment.linked_batch) {
    matchedInvoice = invoices.find(inv => inv.id === (payment.invoice_id || payment.linked_batch));
  }

  // 2. Fuzzy match: same client + close amount (within 1%)
  if (!matchedInvoice && payment.client_id) {
    const candidates = invoices.filter(inv =>
      inv.client_id === payment.client_id &&
      Math.abs(inv.total_amount - payment.amount) / Math.max(inv.total_amount, 1) < 0.01
    );
    if (candidates.length === 1) matchedInvoice = candidates[0];
  }

  if (matchedInvoice) {
    matched.push({ invoiceId: matchedInvoice.id, paymentId: payment.id, amount: payment.amount });
    const isFullPayment = Math.abs(payment.amount - matchedInvoice.total_amount) < 0.01;
    updates.push({
      id: matchedInvoice.id,
      status: isFullPayment ? 'paid' : 'partial',
      paid_amount: payment.amount,
      payment_id: payment.id
    });
  } else {
    unmatched.push({ paymentId: payment.id, amount: payment.amount, clientId: payment.client_id });
  }
});

// Check overdue (invoices older than 30 days)
const now = new Date();
const overdue = invoices.filter(inv => {
  const created = new Date(inv.created_at || inv.issue_date);
  const daysOld = (now - created) / (1000 * 60 * 60 * 24);
  return daysOld > 30 && !updates.find(u => u.id === inv.id);
});

return [{
  json: {
    matchedCount: matched.length,
    unmatchedCount: unmatched.length,
    overdueCount: overdue.length,
    updates: updates,
    overdueInvoices: overdue.map(i => ({ id: i.id, amount: i.total_amount, client: i.client_name || i.client_id })),
    unmatchedPayments: unmatched
  }
}];

const data = $('Match & Reconcile').first().json;

let msg = '🔄 *Daily Reconciliation Report*\n\n';
msg += `✅ Matched: ${data.matchedCount} payments\n`;
msg += `❌ Unmatched: ${data.unmatchedCount} payments\n`;
msg += `⚠️ Overdue: ${data.overdueCount} invoices\n`;

if (data.overdueInvoices && data.overdueInvoices.length > 0) {
  msg += '\n*Overdue Invoices:*\n';
  data.overdueInvoices.forEach(i => {
    msg += `• #${i.id}: $${i.amount} (${i.client})\n`;
  });
}

if (data.unmatchedPayments && data.unmatchedPayments.length > 0) {
  msg += '\n*Unmatched Payments:*\n';
  data.unmatchedPayments.forEach(p => {
    msg += `• Payment #${p.paymentId}: $${p.amount}\n`;
  });
}

return [{ json: { message: msg, hasOverdue: data.overdueCount > 0 } }];
